const generateHistory = (base: number, variance: number, days: number = 14): MetricPoint[] => {
  return Array.from({ length: days }).map((_, i) => ({
    date: `03-${(25 - days + i + 1).toString().padStart(2, '0')}`,
    value: base + (Math.random() - 0.5) * variance
  }));
};

const generateAnnualHistory = (baseMonthly: number) => {
  const months = ['1月', '2月', '3月', '4月', '5月', '6月', '7月', '8月', '9月', '10月', '11月', '12月'];
  const currentMonthIdx = 2; // 假设当前是3月
  return months.map((m, idx) => {
    const seasonality = 1 + Math.sin(idx / 2) * 0.2; // 模拟季节性波动
    const forecast = baseMonthly * seasonality;
    return {
      date: m,
      actual: idx <= currentMonthIdx ? forecast * (0.95 + Math.random() * 0.1) : undefined,
      forecast: forecast
    };
  });
};

