                      <div key={idx} className="relative pl-6 before:absolute before:left-0 before:top-2 before:w-2 before:h-2 before:bg-slate-300 before:rounded-full">
                        <p className="text-sm font-bold text-slate-800">{edu}</p>
                      </div>
                    ))}
                  </div>
               </div>

               <div className="p-6 bg-slate-900 rounded-xl text-white shadow-lg relative overflow-hidden">
                  <div className="absolute -right-4 -top-4 opacity-10 rotate-12"><StickyNote size={80}/></div>
                  <h4 className="flex items-center gap-2 text-[10px] font-black text-blue-400 uppercase tracking-widest mb-4">
                    <StickyNote size={14}/> 运营备注
                  </h4>
                  <p className="text-sm font-bold leading-relaxed italic border-l-2 border-blue-600 pl-4">
                    "{selectedMaker.remarks}"
                  </p>
               </div>
            </div>

            <div className="p-8 border-t border-slate-100 bg-slate-50">
               <div className="text-[10px] text-slate-400 font-bold uppercase text-center">数据更新于: 2024-03-25</div>
            </div>
          </div>
        </div>
      )}

      {/* AI 分析浮动按钮 */}
      <button 
        onClick={handleGenerateInsight}
        disabled={loadingInsight}
        className="fixed bottom-10 right-10 bg-slate-950 text-white px-6 py-3 rounded-full font-black text-xs uppercase tracking-widest hover:bg-blue-600 transition-all border border-slate-800 shadow-2xl flex items-center gap-3 z-50"
      >
        {loadingInsight ? <div className="w-4 h-4 border-2 border-white/20 border-t-white rounded-full animate-spin"></div> : <BrainCircuit size={18} className="text-white"/>}
        生成 AI 分析报告
      </button>

      {/* AI 报告模态框 */}
      {insight && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-slate-950/40 backdrop-blur-sm" onClick={() => setInsight(null)}></div>
            <div className="bg-white rounded border border-slate-200 w-full max-w-2xl relative overflow-hidden flex flex-col max-h-[90vh] shadow-2xl animate-in zoom-in-95 duration-200">
                <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                    <div className="flex items-center gap-2">
                        <Sparkles className="text-blue-600" size={20}/>
                        <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">AI 深度洞察报告</h3>
                    </div>
                    <button onClick={() => setInsight(null)} className="p-1 hover:bg-slate-200 rounded transition-colors text-slate-400"><X size={20}/></button>
                </div>
                <div className="p-8 overflow-y-auto space-y-8">
                    <div className="bg-blue-50/50 p-6 rounded border border-blue-100">
                        <h4 className="text-[10px] font-black text-blue-400 uppercase mb-3 tracking-widest flex items-center gap-2"><TrendingUp size={12}/> 执行摘要</h4>
                        <p className="text-sm text-slate-900 leading-relaxed font-bold">{insight.summary}</p>
                    </div>
                    <div className="space-y-4">
                        <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">建议行动事项</h4>
                        {insight.actionItems.map((item, idx) => (
                            <div key={idx} className="flex gap-4 p-4 border border-slate-100 rounded hover:bg-slate-50 transition-all">
                                <span className="text-[10px] font-black text-white bg-slate-900 w-5 h-5 flex items-center justify-center rounded-full mt-0.5">{idx + 1}</span>
                                <p className="text-sm text-slate-700 font-bold">{item}</p>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
